      .poll(async () => mentionPopup.isVisible().catch(() => false), {
        timeout: 3000,
        intervals: [100, 250, 500],
      })
      .toBeTruthy()
      .then(() => true)
      .catch(() => false);
    if (!popupVisible) {
      await page.keyboard.press('Backspace');
      throw new Error('Mention popup did not open');
    }
